import shioaji as _sj

# Names that the original shioaji.contracts exposed and that consumers may
# import by name (e.g. `from shioaji.contracts import FetchStatus`). The
# `_EXPORTS` set drives the deprecation-shimming __getattr__ below.
#
# Faithful-mirror policy: do NOT add classes that were never in the original
# (e.g. `ContractCategory` is rshioaji-specific). FetchStatus is included
# because it IS a top-level Enum class in the original module
# (`shioaji/contracts.py:32`), even though the original's `__all__` does not
# list it — meaning `from shioaji.contracts import FetchStatus` worked in the
# original despite its absence from `import *`.
_EXPORTS = {
    "BaseContract": "BaseContract",
    "Contract": "Contract",
    "Index": "Index",
    "Stock": "Stock",
    "Future": "Future",
    "Option": "Option",
    "Contracts": "Contracts",
    "ComboBase": "ComboBase",
    "ComboContract": "ComboContract",
    "FetchStatus": "FetchStatus",
}

# `__all__` is decoupled from `_EXPORTS`: it must mirror the original module's
# `__all__` (9 items) so `from shioaji.contracts import *` exposes the same
# surface as the original. FetchStatus is intentionally omitted here even
# though it lives in `_EXPORTS`, exactly matching the original's behavior.
__all__ = (
    "BaseContract",
    "Contract",
    "Index",
    "Stock",
    "Future",
    "Option",
    "Contracts",
    "ComboBase",
    "ComboContract",
)


def __getattr__(name):
    if name in _EXPORTS:
        import warnings
        warnings.warn(
            f"shioaji.contracts.{name} is deprecated, use sj.{_EXPORTS[name]}",
            DeprecationWarning,
            stacklevel=2,
        )
        return getattr(_sj, _EXPORTS[name])
    raise AttributeError(f"module 'shioaji.contracts' has no attribute {name!r}")
